import { type MarkerInteractionState } from '../types/marker.js';

type ThemeOptions = 'light' | 'dark';

const MARKER_DEFAULT_BRIGHTNESS = 1;

const mapStateBrightness: Record<
  ThemeOptions,
  Record<MarkerInteractionState, number>
> = {
  dark: {
    default: MARKER_DEFAULT_BRIGHTNESS,
    hovered: 1.3,
    active: 1.5,
    inactive: 0.65,
  },
  light: {
    default: MARKER_DEFAULT_BRIGHTNESS,
    hovered: 0.8,
    active: 0.65,
    inactive: 1.3,
  },
};

/**
 * Gets the proper slope for the BrightnessFilter depending on the theme and the state of the marker
 *
 * @param theme -
 * @param state -
 */
export const getMarkerBrightnessBasedOnState = (
  theme: ThemeOptions,
  state: MarkerInteractionState,
) => mapStateBrightness[theme][state];
